const filePath = $input.first().json.path ?? '';
// filePath is absolute: /data/vault/enrich/concepts/foo.md

const vaultRoot = '/data/vault';
const enrichPrefix = vaultRoot + '/enrich/';

if (!filePath.startsWith(enrichPrefix)) {
  throw new Error(`Unexpected path outside enrich/: ${filePath}`);
}

const relative = filePath.slice(enrichPrefix.length); // e.g. concepts/foo.md
const parts = relative.split('/');

if (parts.length < 2) {
  throw new Error(`File must be inside a subdirectory of enrich/ (e.g. enrich/concepts/foo.md). Got: ${filePath}`);
}

const subdir = parts[0]; // concepts
const filename = parts.slice(1).join('/'); // foo.md

const validSubdirs = ['concepts', 'topics', 'entities', 'analyses'];
if (!validSubdirs.includes(subdir)) {
  throw new Error(`Unrecognized enrich/ subdirectory '${subdir}'. Valid options: ${validSubdirs.join(', ')}`);
}

const wikiDestPath = `${vaultRoot}/wiki/${subdir}/${filename}`;
const wikiRelativePath = `wiki/${subdir}/${filename}`;

return [{
  json: {
    src_path: filePath,
    wiki_dest_path: wikiDestPath,
    wiki_relative_path: wikiRelativePath
  }
}];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('reindex returned empty stdout');
}
return [{ json: JSON.parse(stdout) }];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('enrich-links returned empty stdout');
}
return [{ json: JSON.parse(stdout) }];

const enrichResult = $input.first().json;
const wikiRelativePath = $node["Resolve Destination"].json.wiki_relative_path;

const payload = {
  operation: 'manual',
  summary: `enrich-links: ${wikiRelativePath}`,
  source_refs: [],
  affected_notes: enrichResult.updated ?? [],
  paths_to_stage: [
    wikiRelativePath,
    ...(enrichResult.updated ?? [])
  ],
  feedback_record_ref: null,
  mutation_result_ref: null,
  commit_message: `enrich-links: add ${wikiRelativePath}`
};

return [{
  json: {
    payload,
    payload_b64: Buffer.from(JSON.stringify(payload), 'utf8').toString('base64')
  }
}];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('commit returned empty stdout');
}
return [{ json: JSON.parse(stdout) }];
